fixed_test_commands.command:
set -e
WORKDIR=/tmp/commons-csv-user-smoke
rm -rf "$WORKDIR"
mkdir -p "$WORKDIR/src/main/java/example"
cat > "$WORKDIR/pom.xml" <<'EOF'
<project xmlns="http://maven.apache.org/POM/4.0.0" xmlns:xsi="http://www.w3.org/2001/XMLSchema-instance"
  xsi:schemaLocation="http://maven.apache.org/POM/4.0.0 https://maven.apache.org/xsd/maven-4.0.0.xsd">
  <modelVersion>4.0.0</modelVersion>
  <groupId>example</groupId>
  <artifactId>commons-csv-user-smoke</artifactId>
  <version>1.0-SNAPSHOT</version>
  <properties>
    <maven.compiler.source>8</maven.compiler.source>
    <maven.compiler.target>8</maven.compiler.target>
  </properties>
  <dependencies>
    <dependency>
      <groupId>org.apache.commons</groupId>
      <artifactId>commons-csv</artifactId>
      <version>1.14.1</version>
    </dependency>
  </dependencies>
</project>
EOF
cat > "$WORKDIR/src/main/java/example/Smoke.java" <<'EOF'
package example;

import java.io.StringReader;
import java.io.StringWriter;
import org.apache.commons.csv.CSVFormat;
import org.apache.commons.csv.CSVParser;
import org.apache.commons.csv.CSVPrinter;
import org.apache.commons.csv.CSVRecord;

public class Smoke {
    public static void main(String[] args) throws Exception {
        try (CSVParser parser = CSVFormat.DEFAULT.parse(new StringReader("a,b,c\n1,2,3\n"))) {
            for (CSVRecord record : parser) {
                System.out.println(record.get(0) + "-" + record.get(1) + "-" + record.get(2));
            }
        }
        StringWriter out = new StringWriter();
        try (CSVPrinter printer = CSVFormat.DEFAULT.builder().setHeader("H1", "H2").build().print(out)) {
            printer.printRecord("x", "y");
        }
        System.out.print(out.toString());
    }
}
EOF
cd "$WORKDIR"
mvn -q -DskipTests compile dependency:build-classpath -Dmdep.outputFile=cp.txt
java -cp target/classes:$(cat cp.txt) example.Smoke
